    constructor(val, left = null, right = null){
        this.val = val;
        this.left = left;
        this.right = right;
    }
}

function inorderTraversalHelper(root, result) {
    if (!root) return;
    inorderTraversalHelper(root.left, result);
    result.push(root.val);
